function initMobileMenu() {
    const toggle = document.getElementById('mobile-menu-toggle');
    const sidebar = document.querySelector('.sidebar');
    if (toggle && sidebar) {
        toggle.addEventListener('click', () => {
            sidebar.classList.toggle('mobile-active');
            const icon = toggle.querySelector('i');
            if (icon) {
                const isOpened = sidebar.classList.contains('mobile-active');
                icon.setAttribute('data-lucide', isOpened ? 'x' : 'menu');
                lucide.createIcons();
            }
        });
        
        // Close on nav click
        document.querySelectorAll('.nav-item').forEach(item => {
            item.addEventListener('click', () => {
                sidebar.classList.remove('mobile-active');
                const menuIcon = document.querySelector('#mobile-menu-toggle i');
                if (menuIcon) {
                    menuIcon.setAttribute('data-lucide', 'menu');
                    lucide.createIcons();
                }
            });
        });
    }
}

// IndexedDB Vault for PDF evidence
let db;
function initVault() {
    const request = indexedDB.open('BioGuardVault', 1);
    request.onupgradeneeded = (e) => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains('evidence')) {
            db.createObjectStore('evidence', { keyPath: 'id' });
        }
    };
    request.onsuccess = (e) => { db = e.target.result; };
}

async function storeEvidence(file) {
    if (!db) return null;
    const id = 'vlt_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
    return new Promise((resolve, reject) => {
        const transaction = db.transaction(['evidence'], 'readwrite');
        const store = transaction.objectStore('evidence');
        store.put({ id: id, name: file.name, blob: file, type: file.type });
        transaction.oncomplete = () => resolve(id);
        transaction.onerror = () => reject(transaction.error);
    });
}

async function getEvidence(id) {
    if (!db || !id) return null;
    return new Promise((resolve) => {
        const transaction = db.transaction(['evidence'], 'readonly');
        const store = transaction.objectStore('evidence');
        const request = store.get(id);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => resolve(null);
    });
}

window.downloadEvidence = async function(id) {
    const data = await getEvidence(id);
    if (!data) {
        alert("Evidencia no encontrada en la bóveda local.");
        return;
    }
    const url = URL.createObjectURL(data.blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = data.name;
    document.body.appendChild(a);
    a.click();
    URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

// =============================================
// AUTH - Supabase Authentication & RBAC
// =============================================
let currentUser = null;
let currentRole = 'viewer'; // default safe role

function initAuth() {
    const overlay = document.getElementById('login-overlay');
    const appContainer = document.getElementById('app-container');

    // Show login overlay immediately
    overlay.classList.add('active');
    appContainer.style.display = 'none';

    if (!supabaseClient) {
        // Fallback: no Supabase client, allow local use
        overlay.classList.remove('active');
        appContainer.style.display = 'flex';
        initApp();
        initVault();
        return;
    }

    // Listen for auth state changes
    supabaseClient.auth.onAuthStateChange(async (event, session) => {
        if (session && session.user) {
            currentUser = session.user;
            await loadUserProfile(currentUser);
            overlay.classList.remove('active');
            appContainer.style.display = 'flex';
            initApp();
            initVault();
            applyRBAC();
        } else {
            currentUser = null;
            currentRole = 'viewer';
            overlay.classList.add('active');
            appContainer.style.display = 'none';
        }
    });

    // Handle login form
    const loginForm = document.getElementById('login-form');
    if (loginForm) {
        loginForm.addEventListener('submit', async (e) => {
            e.preventDefault();
            const email = document.getElementById('login-email').value.trim();
            const password = document.getElementById('login-password').value;
            const errEl = document.getElementById('login-error');
            const btnText = document.getElementById('login-btn-text');
            const btn = loginForm.querySelector('button[type="submit"]');

            errEl.classList.add('hidden');
            btn.disabled = true;
            btnText.textContent = 'Verificando...';

            try {
                const { error } = await supabaseClient.auth.signInWithPassword({ email, password });

                if (error) {
                    console.error("Login Auth Error:", error);
                    let errorMsg = 'Credenciales incorrectas.';
                    if (error.message.toLowerCase().includes('email not confirmed')) {
                        errorMsg = 'Debés confirmar tu correo electrónico. Revisá tu mail (SPAM).';
                    } else if (error.message.toLowerCase().includes('invalid login credentials')) {
                        errorMsg = 'Correo o contraseña incorrectos. Verificá los datos.';
                    } else {
                        errorMsg = 'Error: ' + error.message;
                    }
                    errEl.textContent = errorMsg;
                    errEl.classList.remove('hidden');
                    btn.disabled = false;
                    btnText.textContent = 'Ingresar Segurizado';
                }
            } catch (err) {
                console.error("Login Exception:", err);
                errEl.textContent = "Error de conexión con el servidor.";
                errEl.classList.remove('hidden');
                btn.disabled = false;
                btnText.textContent = 'Ingresar Segurizado';
            }
        });
    }
}

async function loadUserProfile(user) {
    // Try to get profile from user_profiles table
    if (!supabaseClient) return;
    try {
        const { data } = await supabaseClient
            .from('user_profiles')
            .select('full_name, role, establishment')
            .eq('id', user.id)
            .single();

        if (data) {
            currentRole = data.role || 'viewer';
            const nameEl = document.getElementById('user-name');
            const estEl = document.getElementById('user-establishment');
            const avatarEl = document.getElementById('user-avatar');
            if (nameEl) nameEl.textContent = data.full_name || user.email;
            if (estEl) {
                estEl.textContent = (currentRole === 'developer' ? 'DESARROLLADOR' : currentRole.toUpperCase());
                estEl.className = 'user-role-badge' + (currentRole === 'developer' ? ' dev-role' : '');
            }
            if (avatarEl) {
                const parts = (data.full_name || user.email).trim().split(' ');
                let initials = parts[0].charAt(0).toUpperCase();
                if (parts[1]) initials += parts[1].charAt(0).toUpperCase();
                avatarEl.textContent = initials;
            }
        } else {
            currentRole = 'viewer';
            const nameEl = document.getElementById('user-name');
            if (nameEl) nameEl.textContent = user.email;
        }
    } catch(e) { console.error('Error loading profile:', e); }
}

function applyRBAC() {
    console.log("Applying RBAC for role:", currentRole);
    // Hide 'Registrar' nav item for viewers
    const navRegister = document.getElementById('nav-register');
    if (navRegister) {
        if (currentRole === 'viewer') {
            navRegister.classList.add('role-hidden');
            navRegister.classList.remove('role-visible');
        } else {
            navRegister.classList.remove('role-hidden');
            navRegister.classList.add('role-visible');
        }
    }
    // Show Users nav only for admins and developers
    const navUsers = document.getElementById('nav-users');
    if (navUsers) {
        if (currentRole === 'admin' || currentRole === 'developer') {
            navUsers.classList.add('role-visible');
            navUsers.classList.remove('role-hidden');
            navUsers.style.display = 'flex';
        } else {
            navUsers.classList.remove('role-visible');
            navUsers.classList.add('role-hidden');
            navUsers.style.display = 'none';
        }
    }
    
    // Toggle Demo Sections based on mode
    const demoSections = document.querySelectorAll('.scenario-intro, #active-scenario-tag');
    demoSections.forEach(s => {
        if (isDemoMode) {
            s.classList.remove('hidden');
        } else {
            s.classList.add('hidden');
        }
    });

    // Developer Specifics
    const devBadges = document.querySelectorAll('.dev-badge');
    devBadges.forEach(b => b.style.display = (currentRole === 'developer' ? 'inline-block' : 'none'));
}

